import{_ as e,o as r,c as o,a3 as l}from"./chunks/framework.oxq6d-og.js";const u=JSON.parse('{"title":"Sorun giderme","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting.md","filePath":"troubleshooting.md"}'),n={name:"troubleshooting.md"};function i(d,a,t,s,c,h){return r(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="sorun-giderme" tabindex="-1">Sorun giderme <a class="header-anchor" href="#sorun-giderme" aria-label="Permalink to &quot;Sorun giderme&quot;">​</a></h1><p>Bir hata mesajını tek başına değil, çağrının hangi aşamasında oluştuğuyla birlikte değerlendirin. NThread, accessor ve hook katmanları aynı process üzerinde çalıştığı için aynı <code>timeout</code> belirtisi farklı nedenlerden çıkabilir.</p><h2 id="baslatma-hataları" tabindex="-1">Başlatma hataları <a class="header-anchor" href="#baslatma-hataları" aria-label="Permalink to &quot;Başlatma hataları&quot;">​</a></h2><h3 id="nosleepaddresserror-nopushretaddresserror-nojumpaddresserror" tabindex="-1"><code>NoSleepAddressError</code> / <code>NoPushretAddressError</code> / <code>NoJumpAddressError</code> <a class="header-anchor" href="#nosleepaddresserror-nopushretaddresserror-nojumpaddresserror" aria-label="Permalink to &quot;`NoSleepAddressError` / `NoPushretAddressError` / `NoJumpAddressError`&quot;">​</a></h3><p>NThread&#39;in ihtiyaç duyduğu küçük talimat stub&#39;ları sistem modüllerinde bulunamadı veya tarama tamamlanmadan kullanıma geçildi.</p><p>Kontrol sırası:</p><ol><li>Process&#39;in Windows x64 olduğundan emin olun.</li><li><code>ntdll</code>, <code>kernel32</code> ve <code>kernelbase</code> modüllerinin hedefte yüklü olduğunu kontrol edin.</li><li>Async başlatmada <code>await memory.init()</code> tamamlanmadan <code>call</code> yapılmadığını doğrulayın.</li><li>Wine kullanıyorsanız Windows Bun sürümünü ve Wine prefix mimarisini kontrol edin.</li></ol><h3 id="access-denied" tabindex="-1">Access denied <a class="header-anchor" href="#access-denied" aria-label="Permalink to &quot;Access denied&quot;">​</a></h3><p>Bu hata her zaman izin eksikliği anlamına gelmez. Hedef process kapanıyor olabilir, thread ID artık geçerli olmayabilir veya istenen Win32 erişim maskesi hedefin güvenlik politikasına uymuyor olabilir. Önce process/thread yaşamını, sonra erişim haklarını inceleyin.</p><h2 id="cagrı-hataları" tabindex="-1">Çağrı hataları <a class="header-anchor" href="#cagrı-hataları" aria-label="Permalink to &quot;Çağrı hataları&quot;">​</a></h2><h3 id="calltimeouterror" tabindex="-1"><code>CallTimeoutError</code> <a class="header-anchor" href="#calltimeouterror" aria-label="Permalink to &quot;`CallTimeoutError`&quot;">​</a></h3><p>Hedef fonksiyon dönüş zinciriyle spin stub&#39;a dönmedi. En yaygın nedenler:</p><ul><li>fonksiyon uzun sürüyor veya bloke oluyor,</li><li>yanlış adres ya da yanlış calling convention kullanılıyor,</li><li>hedef thread lock/loader bölgesinde askıya alınmış durumda,</li><li>thread başka bir kod yolu tarafından sonlandırıldı,</li><li>hook veya başka bir suspend/resume sahibi ile suspend sayacı çakıştı.</li></ul><p>Timeout sonrasında aynı context&#39;i tekrar yazmadan önce hedef thread&#39;in <code>exit code</code>, <code>RIP</code> ve <code>RSP</code> durumunu okuyun. <code>timeoutMs</code> değerini yükseltmek yalnızca çağrının gerçekten uzun sürdüğü doğrulanmışsa anlamlıdır.</p><h3 id="callthreaddiederror" tabindex="-1"><code>CallThreadDiedError</code> <a class="header-anchor" href="#callthreaddiederror" aria-label="Permalink to &quot;`CallThreadDiedError`&quot;">​</a></h3><p>Thread, çağrı sırasında öldü veya context okunamaz hale geldi. <code>ExitThread</code> veya noreturn fonksiyonları NThread çağrısı olarak kullanmayın. Hedefi yeniden başlatıp aynı çağrıyı daha küçük ve geri dönen bir fonksiyonla izole edin.</p><h3 id="stack-mismatch-uyarısı" tabindex="-1">Stack mismatch uyarısı <a class="header-anchor" href="#stack-mismatch-uyarısı" aria-label="Permalink to &quot;Stack mismatch uyarısı&quot;">​</a></h3><p><code>expectedRsp</code> ayarlanmışsa bu denetim hem async <code>call()</code> hem <code>callSync()</code> dönüşünde yapılır. Çağrı sonrası gerçek <code>RSP</code>, beklenen değerden farklıysa yanlış ABI, eksik stack argümanı, çağrının stack&#39;i değiştirmesi veya dönüş stub&#39;ının beklenmeyen bir yoldan çalışması söz konusu olabilir. Uyarıyı görmezden gelip aynı thread&#39;de art arda çağrılar yapmak bir sonraki <code>ret</code> sırasında crash&#39;e dönüşebilir.</p><h2 id="hook-hataları" tabindex="-1">Hook hataları <a class="header-anchor" href="#hook-hataları" aria-label="Permalink to &quot;Hook hataları&quot;">​</a></h2><h3 id="hook-hit-alınmıyor" tabindex="-1">Hook hit alınmıyor <a class="header-anchor" href="#hook-hit-alınmıyor" aria-label="Permalink to &quot;Hook hit alınmıyor&quot;">​</a></h3><p>Hedef fonksiyon hiç çağrılmıyor olabilir; yanlış modül sürümündeki adres kullanılmış olabilir veya hook yanlış process&#39;e yazılmış olabilir. Önce <code>originalBytes</code> ile hedefteki byte&#39;ları ve process PID&#39;sini doğrulayın.</p><h3 id="hook-disable-sonrası-crash" tabindex="-1">Hook disable sonrası crash <a class="header-anchor" href="#hook-disable-sonrası-crash" aria-label="Permalink to &quot;Hook disable sonrası crash&quot;">​</a></h3><p>Disable sırasında park edilmiş thread&#39;ler hâlâ eski <code>EB FE</code> konumunda olabilir veya özgün byte&#39;lar tam talimat sınırında geri yüklenmemiş olabilir. <code>poll()</code> ile bekleyen hit&#39;leri tüketin, <code>disable()</code> tamamlanmadan process&#39;i kapatmayın ve <code>destroy()</code> çağrısını en sona bırakın.</p><h3 id="minhook-detour-calısmıyor" tabindex="-1">MinHook detour çalışmıyor <a class="header-anchor" href="#minhook-detour-calısmıyor" aria-label="Permalink to &quot;MinHook detour çalışmıyor&quot;">​</a></h3><p>Detour adresi 32-bit relative jump sınırının dışında olabilir. MinHook bunu yakın relay ile çözmeye çalışır; relay allocation/protection başarısızsa hedefin adres alanını ve <code>allocNear</code> yeteneğini kontrol edin. Ayrıca detour machine-code&#39;un hedef process&#39;e gerçekten taşındığını doğrulayın.</p><h2 id="tanı-icin-loglama" tabindex="-1">Tanı için loglama <a class="header-anchor" href="#tanı-icin-loglama" aria-label="Permalink to &quot;Tanı için loglama&quot;">​</a></h2><p>Sorunu tekrar üretirken şu değerleri aynı çağrı için kaydedin:</p><ul><li>hedef PID ve driving thread ID,</li><li>hedef fonksiyon adresi ve ilk byte&#39;ları,</li><li>çağrı öncesi/sonrası <code>RIP</code>, <code>RSP</code>, <code>RCX</code>, <code>RDX</code>, <code>RAX</code>,</li><li>argüman türleri ve stack argümanı sayısı,</li><li>timeout sonucu ve thread exit durumu.</li></ul><p>Adresleri loglarken hex formatı kullanın; pointer değerlerini JavaScript <code>number</code> içine zorlayarak 64-bit hassasiyetini kaybetmeyin.</p>',29)])])}const k=e(n,[["render",i]]);export{u as __pageData,k as default};
